const ROUTE_NAMES = {
  "1":  "Жмеринка–Вінниця–Хмельницький–Тернопіль–Львів",
  "2":  "Вінниця–Вороновиця–Гайсин",
  "3":  "Шаргород–Піщанка",
  "4":  "Жмеринка–Чечельник–Жабокричка",
  "5":  "Немирів–Гайсин–Монастирище",
  "6":  "Літин–Уланів",
  "7":  "Оратів–Тетіїв",
  "8":  "Калинівка–Козятин–Білилівка",
  "9":  "Муровані Курилівці–Ямпіль",
  "10": "Бар–Струга",
  "11": "Наддністрянське–Костичани",
  "12": "Жмеринка–Бердичів–Житомир–Київ–Біла Церква",
  "13": "Гайсин–Умань"
};

function haversineKm(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2)
          + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180)
          * Math.sin(dLng/2) * Math.sin(dLng/2);
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function minDistToRoute(lat, lng, points) {
  let minDist = Infinity;
  for (const point of points) {
    const d = haversineKm(lat, lng, point[0], point[1]);
    if (d < minDist) minDist = d;
  }
  return minDist;
}

// Знаходимо найближчий маршрут
let bestDist = Infinity;
let bestRouteId = null;

for (const routeId of Object.keys(ROUTE_POLYLINES)) {
  const dist = minDistToRoute(clientLat, clientLng, ROUTE_POLYLINES[routeId]);
  if (dist < bestDist) {
    bestDist = dist;
    bestRouteId = routeId;
  }
}

const dist = Math.round(bestDist * 10) / 10;
const routeName = ROUTE_NAMES[bestRouteId] || ('Маршрут ' + bestRouteId);

// Тариф
let status, price, priceRange, zone;

if (dist <= 2) {
  status = 'on_route';
  price = null;
  priceRange = '500–900';
  zone = 'Місто знаходиться на маршруті заводу';
} else if (dist <= 15) {
  status = 'deviation';
  price = 900;
  priceRange = null;
  zone = `Відхилення ${dist} км від маршруту`;
} else if (dist <= 20) {
  status = 'deviation';
  price = 1100;
  priceRange = null;
  zone = `Відхилення ${dist} км від маршруту`;
} else if (dist <= 40) {
  const extra = Math.ceil(dist - 20);
  price = 1100 + extra * 35;
  priceRange = null;
  status = 'deviation';
  zone = `Відхилення ${dist} км від маршруту`;
} else if (dist <= 45) {
  status = 'clarify';
  price = null;
  priceRange = null;
  zone = `Відхилення ${dist} км — потребує уточнення у менеджера`;
} else {
  status = 'nova_poshta';
  price = 4000;
  priceRange = null;
  zone = `Відстань ${dist} км — доставка Новою Поштою`;
}

return [{
  json: {
    status,
    price,
    priceRange,
    zone,
    distanceKm: dist,
    cityFound: cityName,
    routeName,
    meetOnRoad: {
      price: 350,
      note: `Зустріч на трасі (маршрут: ${routeName}) — за попередньою домовленістю з водієм (очікування 15 хв)`
    }
  }
}];
